import{_ as s,H as e,f as p,i as n}from"./chunks/framework.BHvCMIhP.js";const N=JSON.parse('{"title":"DNS 解析:记录类型,TTL,权威 DNS,递归 DNS","description":"","frontmatter":{},"headers":[],"relativePath":"cloudBasicsLearning/03-DNS解析.md","filePath":"cloudBasicsLearning/03-DNS解析.md","lastUpdated":1779015580000}'),l={name:"cloudBasicsLearning/03-DNS解析.md"};function t(i,a,o,c,d,h){return e(),p("div",null,[...a[0]||(a[0]=[n(`<h1 id="dns-解析-记录类型-ttl-权威-dns-递归-dns" tabindex="-1">DNS 解析:记录类型,TTL,权威 DNS,递归 DNS <a class="header-anchor" href="#dns-解析-记录类型-ttl-权威-dns-递归-dns" aria-label="Permalink to &quot;DNS 解析:记录类型,TTL,权威 DNS,递归 DNS&quot;">​</a></h1><h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p>DNS 解析就是把域名翻译成网络能访问的地址,让浏览器知道 <code>example.com</code> 应该去找哪台服务器,哪个 CDN 或哪个邮件服务.</p><p>它最容易被误解成&quot;我在控制台里填一条记录,全世界马上生效&quot;.真实情况是,DNS 是一个分层查询和缓存系统,你改的是权威 DNS 里的答案,但用户拿到的是递归 DNS 缓存后的答案.</p><p>最小心智模型是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>权威 DNS = 真正保存你域名解析记录的地方</span></span>
<span class="line"><span>递归 DNS = 用户网络运营商,公共 DNS 或公司网络帮用户查询并缓存答案的地方</span></span>
<span class="line"><span>TTL = 这份答案可以被缓存多久</span></span></code></pre></div><p>所以你改了 DNS 后,有些人马上看到新网站,有些人还访问旧网站,不一定是云厂商坏了,可能只是不同递归 DNS 的缓存还没过期.</p><h2 id="放在系统哪里" tabindex="-1">放在系统哪里 <a class="header-anchor" href="#放在系统哪里" aria-label="Permalink to &quot;放在系统哪里&quot;">​</a></h2><p>DNS 发生在真正访问网站之前.</p><p>一次访问链路可以简化成这样:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>浏览器输入 https://www.example.com</span></span>
<span class="line"><span>  -&gt; 查询 www.example.com 的 DNS 记录</span></span>
<span class="line"><span>  -&gt; 得到 IP,CNAME 或 CDN 地址</span></span>
<span class="line"><span>  -&gt; 建立 TCP / TLS 连接</span></span>
<span class="line"><span>  -&gt; 发送 HTTP 请求</span></span>
<span class="line"><span>  -&gt; 服务器返回页面</span></span></code></pre></div><p>DNS 不负责返回网页内容.它只回答&quot;这个名字应该去哪里&quot;.</p><p>常见记录可以按场景理解:</p><ul><li>A 记录:把域名指向一个 IPv4 地址,例如 <code>203.0.113.10</code>.</li><li>AAAA 记录:把域名指向一个 IPv6 地址.</li><li>CNAME 记录:把一个名字指向另一个名字,例如 <code>www.example.com -&gt; your-app.vercel.app</code>.</li><li>MX 记录:告诉别人这个域名的邮件应该投递到哪里.</li><li>TXT 记录:常用于域名验证,邮件防伪,第三方服务校验.</li><li>NS 记录:告诉上层 DNS,这个域名应该由哪些权威 DNS 服务器管理.</li></ul><p>独立开发者最常接触的是 A,CNAME,TXT.比如:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>把根域名 example.com 指到一台云服务器:</span></span>
<span class="line"><span>  A example.com -&gt; 203.0.113.10</span></span>
<span class="line"><span></span></span>
<span class="line"><span>把 www 指到前端托管平台:</span></span>
<span class="line"><span>  CNAME www.example.com -&gt; project.pages.dev</span></span>
<span class="line"><span></span></span>
<span class="line"><span>给邮件服务做验证:</span></span>
<span class="line"><span>  TXT example.com -&gt; 一段服务商要求你添加的字符串</span></span></code></pre></div><p>如果你不理解这些记录的用途,就很容易在同一个主机名上乱加记录.比如 <code>www.example.com</code> 同时配置 A 和 CNAME,很多 DNS 服务会直接拒绝,因为 CNAME 的意思是&quot;这个名字完全交给另一个名字&quot;,不能再同时塞别的答案.</p><h2 id="常见套餐和使用限制" tabindex="-1">常见套餐和使用限制 <a class="header-anchor" href="#常见套餐和使用限制" aria-label="Permalink to &quot;常见套餐和使用限制&quot;">​</a></h2><p>DNS 看起来很小,但它有几个非常实际的限制.</p><h3 id="_1-记录数量和高级能力" tabindex="-1">1. 记录数量和高级能力 <a class="header-anchor" href="#_1-记录数量和高级能力" aria-label="Permalink to &quot;1. 记录数量和高级能力&quot;">​</a></h3><p>免费 DNS 通常足够管理小网站,但可能限制记录数量,负载均衡,健康检查,地理线路,审计日志,API 调用频率.</p><p>个人项目一般用不到高级能力.真正需要关注的是:记录能不能稳定解析,控制台是否清晰,是否支持基本的 DNSSEC,是否有变更记录.</p><h3 id="_2-ttl-不是越低越好" tabindex="-1">2. TTL 不是越低越好 <a class="header-anchor" href="#_2-ttl-不是越低越好" aria-label="Permalink to &quot;2. TTL 不是越低越好&quot;">​</a></h3><p>TTL 表示递归 DNS 可以缓存多久.例如 TTL 是 300 秒,理论上最多 5 分钟后用户会重新查询.</p><p>上线迁移时,你可能想把 TTL 调低,这样切换 IP 更快.但 TTL 太低也会增加 DNS 查询量,在大流量场景下可能带来额外成本或压力.</p><p>小团队常见做法:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>平时 TTL 设置为 5-30 分钟</span></span>
<span class="line"><span>迁移前一天调低到 1-5 分钟</span></span>
<span class="line"><span>迁移完成且稳定后再调回正常值</span></span></code></pre></div><p>注意:如果你迁移前才把 TTL 调低,旧的高 TTL 可能已经被缓存了.TTL 调整也需要提前生效.</p><h3 id="_3-根域名和-cname-的限制" tabindex="-1">3. 根域名和 CNAME 的限制 <a class="header-anchor" href="#_3-根域名和-cname-的限制" aria-label="Permalink to &quot;3. 根域名和 CNAME 的限制&quot;">​</a></h3><p>很多平台会让你把 <code>www.example.com</code> CNAME 到它们的域名,这很简单.但根域名 <code>example.com</code> 传统上不能直接配置 CNAME,因为根域名还需要承载 NS,SOA 等记录.</p><p>一些 DNS 服务提供 ALIAS,ANAME 或 CNAME flattening,可以在体验上解决这个问题.但这些不是 DNS 标准里最基础的记录类型,不同厂商叫法和行为不完全一样.</p><p>这就是为什么很多小团队会选择:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>example.com      -&gt; 跳转到 www.example.com</span></span>
<span class="line"><span>www.example.com  -&gt; CNAME 到托管平台</span></span></code></pre></div><p>这样简单,稳定,排障也容易.</p><h3 id="_4-dns-故障不是网站故障" tabindex="-1">4. DNS 故障不是网站故障 <a class="header-anchor" href="#_4-dns-故障不是网站故障" aria-label="Permalink to &quot;4. DNS 故障不是网站故障&quot;">​</a></h3><p>有时候服务器是好的,但用户还是打不开网站.原因可能是:</p><ul><li>权威 DNS 配错.</li><li>NS 改到了另一个平台.</li><li>递归 DNS 缓存了旧答案.</li><li>DNSSEC 配置错误导致验证失败.</li><li>某些地区的网络无法访问某个 DNS 服务.</li></ul><p>排障时不要只看服务器日志.如果服务器没有任何请求进来,先查 DNS.</p><h2 id="小团队建议" tabindex="-1">小团队建议 <a class="header-anchor" href="#小团队建议" aria-label="Permalink to &quot;小团队建议&quot;">​</a></h2><p>DNS 管理要追求&quot;少,清楚,可恢复&quot;.</p><p>最低限度建议:</p><ul><li>明确一个主 DNS 托管商,不要在多个平台同时改记录.</li><li>记录根域名,<code>www</code>,<code>api</code>,<code>admin</code>,邮件相关记录分别指向哪里.</li><li>对生产域名的 DNS 变更写简单变更备注.</li><li>迁移前提前降低 TTL.</li><li>不要随手删除 TXT,MX 记录,它们可能关系到邮件,证书或第三方验证.</li><li>为正式业务保留 <code>www</code> 和根域名的统一跳转策略.</li></ul><p>真实场景里,新手常说&quot;DNS 还没生效&quot;.这句话太粗.你应该继续问三个问题:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 当前域名的 NS 指向谁?</span></span>
<span class="line"><span>2. 权威 DNS 里查到的答案是什么?</span></span>
<span class="line"><span>3. 用户本地递归 DNS 查到的答案是什么?</span></span></code></pre></div><p>如果权威 DNS 已经是新答案,但用户本地还是旧答案,大概率是缓存.如果权威 DNS 里就是错的,那就是你配置错了.</p><p>什么时候基础 DNS 够用?</p><p>大多数独立项目,落地页,SaaS 早期,一个普通 DNS 托管商就够.你需要的是稳定解析和清晰控制台,不是复杂线路调度.</p><p>什么时候升级?</p><p>当你需要多地域容灾,健康检查自动切换,企业审计,细粒度权限,超高查询量或严格可用性承诺时,再考虑更专业的 DNS 方案.</p><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><p>DNS 解析不是&quot;填一条记录就完事&quot;,而是权威 DNS 给答案,递归 DNS 缓存答案,TTL 控制缓存时间;小团队把 NS,记录类型和 TTL 搞清楚,就能避开大多数上线事故.</p>`,51)])])}const u=s(l,[["render",t]]);export{N as __pageData,u as default};
